#include <stdio.h>
#include <string.h>
#include <stdlib.h>

#define MAX_EXT 11
#define MAX_TYPE 51
#define MAX_NAME 51

typedef struct Node { char ext[MAX_EXT]; char type[MAX_TYPE]; struct Node* next; } Node;

unsigned long hash(const char *s) {
    unsigned long h = 5381;
    for (; *s; ++s) h = ((h << 5) + h) + (unsigned char)*s;
    return h;
}

int main() {
    int T; if (scanf("%d", &T)!=1) return 0;
    while (T--) {
        int N, Q; scanf("%d %d", &N, &Q);
        // simple hash table with chaining, size enough for N<=100
        const int SZ = 211;
        Node* table[SZ]; memset(table, 0, sizeof(table));
        for (int i=0;i<N;++i) {
            char ext[MAX_EXT]; char type[MAX_TYPE];
            scanf("%s %s", ext, type);
            unsigned long h = hash(ext) % SZ;
            Node* n = (Node*)malloc(sizeof(Node));
            strcpy(n->ext, ext); strcpy(n->type, type); n->next = table[h];
            table[h] = n;
        }
        char name[MAX_NAME];
        for (int i=0;i<Q;++i) {
            scanf("%s", name);
            char *p = strrchr(name, '.');
            if (!p || *(p+1)=='\0') {
                printf("unknown\n");
                continue;
            }
            char *ext = p+1;
            unsigned long h = hash(ext) % SZ;
            Node* cur = table[h];
            while (cur && strcmp(cur->ext, ext)!=0) cur = cur->next;
            if (cur) printf("%s\n", cur->type);
            else printf("unknown\n");
        }
        // free memory
        for (int i=0;i<SZ;++i) {
            Node* cur = table[i];
            while (cur) { Node* tmp = cur; cur = cur->next; free(tmp); }
        }
    }
    return 0;
}

