using namespace std;
int main(){
    ios::sync_with_stdio(false);
    cin.tie(nullptr);
    int T; if(!(cin>>T)) return 0;
    while(T--){
        int N,Q; cin>>N>>Q;
        unordered_map<string,string> mp;
        mp.reserve(N*2);
        for(int i=0;i<N;++i){
            string ext, typ; cin>>ext>>typ; mp[ext]=typ;
        }
        string name;
        for(int i=0;i<Q;++i){
            cin>>name;
            size_t pos = name.rfind('.');
            if(pos==string::npos || pos+1==name.size()){
                cout<<"unknown\n";
                continue;
            }
            string ext = name.substr(pos+1);
            auto it = mp.find(ext);
            if(it!=mp.end()) cout<<it->second<<"\n";
            else cout<<"unknown\n";
        }
    }
    return 0;
}

