#!/usr/bin/env python3
import sys
def solve():
    data = sys.stdin.read().splitlines()
    if not data:
        return
    it = iter(data)
    T = int(next(it))
    out_lines = []
    for _ in range(T):
        N_Q = next(it).split()
        while len(N_Q) < 2:  # handle possible empty lines
            N_Q = next(it).split()
        N, Q = map(int, N_Q)
        mp = {}
        for _ in range(N):
            ext, typ = next(it).split()
            mp[ext] = typ
        for _ in range(Q):
            name = next(it)
            pos = name.rfind('.')
            if pos == -1 or pos == len(name) - 1:
                out_lines.append('unknown')
            else:
                ext = name[pos+1:]
                out_lines.append(mp.get(ext, 'unknown'))
    sys.stdout.write('\n'.join(out_lines))
if __name__ == "__main__":
    solve()

